// DATA HOOKS — Supabase only, scoped to user via Row Level Security
// ══════════════════════════════════════════════════════════════════════════
const useVials = (userId) => {
  const [vials,   setVials]   = useState([]);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    if(!userId) return;
    const {data,error} = await supabase.from("vials").select("*").order("created_at",{ascending:true});
    // Sort client-side: sort_order first (nulls last), then created_at
    const sorted = (data||[]).sort((a,b)=>{
      const ao = a.sort_order ?? 999999;
      const bo = b.sort_order ?? 999999;
      if(ao !== bo) return ao - bo;
      return new Date(a.created_at) - new Date(b.created_at);
    });
    setVials(sorted);
    setLoading(false);
  },[userId]);

  useEffect(()=>{ load(); },[load]);

  const addVial = async (v) => {
    const {data,error} = await supabase.from("vials").insert({
      user_id:userId, name:v.name, total_mg:+v.totalMg,
      remaining_mg:+v.totalMg, dot:v.dot||null, notes:v.notes||null,
      status:v.status||"powder",
      bac_water_ml:v.bacWaterMl?+v.bacWaterMl:null,
      shape:v.shape||"circle",
      standard_dose_iu:v.standardDoseIu?+v.standardDoseIu:null,
      dose_unit:v.doseUnit||"mcg",
      cost_paid:v.costPaid?+v.costPaid:null,
    }).select().single();
    if(error){
      console.error("addVial error:", JSON.stringify(error));
      return { error };
    }
    if(data) setVials(s=>[...s,data]);
    return { data };
  };

  const updateVial = async (id,v) => {
    const patch = {
      name:v.name, total_mg:+v.totalMg, remaining_mg:+v.remaining,
      dot:v.dot||null, notes:v.notes||null,
      status:v.status||"powder",
      bac_water_ml:v.bacWaterMl?+v.bacWaterMl:null,
      shape:v.shape||"circle",
      standard_dose_iu:v.standardDoseIu?+v.standardDoseIu:null,
      dose_unit:v.doseUnit||"mcg",
      cost_paid:v.costPaid?+v.costPaid:null,
    };
    await supabase.from("vials").update(patch).eq("id",id);
    setVials(s=>s.map(x=>x.id===id?{...x,...patch}:x));
  };

  const deductVial = async (id,mgAmount) => {
    const vial = vials.find(x=>x.id===id);
    if(!vial) return;
    const newRem = Math.max(0,+(vial.remaining_mg-mgAmount).toFixed(4));
    await supabase.from("vials").update({remaining_mg:newRem}).eq("id",id);
    setVials(s=>s.map(x=>x.id===id?{...x,remaining_mg:newRem}:x));
  };

  const deleteVial = async (id) => {
    await supabase.from("vials").delete().eq("id",id);
    setVials(s=>s.filter(x=>x.id!==id));
  };

  // Persist new order for a group after drag-drop
  const reorderVials = async (reordered) => {
    // Optimistically update UI immediately
    setVials(current => {
      const ids = new Set(reordered.map(v=>v.id));
      const others = current.filter(v=>!ids.has(v.id));
      return [...reordered, ...others];
    });
    // Write sort_order to Supabase for each vial in the group
    await Promise.all(
      reordered.map((v,i) => supabase.from("vials").update({sort_order:i}).eq("id",v.id))
    );
  };

  return {vials,loading,addVial,updateVial,deductVial,deleteVial,reorderVials};
};

// protocols module removed — replaced by Calendar

const useLog = (userId) => {
  const [entries, setEntries] = useState([]);

  useEffect(()=>{
    if(!userId) return;
    supabase.from("injection_log").select("*").order("injected_at",{ascending:false})
      .then(({data})=>setEntries(data||[]));
  },[userId]);

  const addEntry = async (e) => {
    const {data} = await supabase.from("injection_log").insert({
      user_id:userId, vial_id:e.vialId, vial_name:e.vialName, vial_dot:e.vialDot||null,
      dose_mcg:e.doseMcg?+e.doseMcg:null, dose_iu:e.doseIU?+e.doseIU:null,
      dose_ml:e.doseML?+e.doseML:null, injected_at:new Date(e.timestamp).toISOString(),
      notes:e.notes||null
    }).select().single();
    if(data) setEntries(s=>[data,...s]);
  };

  const deleteEntry = async (id) => {
    await supabase.from("injection_log").delete().eq("id",id);
    setEntries(s=>s.filter(x=>x.id!==id));
  };

  return {entries,addEntry,deleteEntry};
};

// ══════════════════════════════════════════════════════════════════════════
// CALCULATOR
// ══════════════════════════════════════════════════════════════════════════
const Calculator = () => {
  const [peptideMg,  setPeptideMg]  = useState("");
  const [bacWaterMl, setBacWaterMl] = useState(1);
  const [desiredMcg, setDesiredMcg] = useState("");
  const [syringeIU,  setSyringeIU]  = useState("100");
  const [result,     setResult]     = useState(null);

  const calculate = () => {
    const mg=parseFloat(peptideMg),bac=parseFloat(bacWaterMl),mcg=parseFloat(desiredMcg),iu=parseFloat(syringeIU);
    if(!mg||!bac||!mcg||!iu) return;
    const mcgPerMl=(mg*1000)/bac, mlNeeded=mcg/mcgPerMl;
    setResult({mcgPerMl,mlNeeded,iuNeeded:mlNeeded*iu});
  };

  return (
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      <Card>
        <p style={{fontSize:13,color:T.textSub,margin:"0 0 16px"}}>Enter your vial info and desired dose to get exact syringe measurements.</p>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <NumInput label="Peptide (mg)" placeholder="e.g. 5" value={peptideMg} onChange={e=>setPeptideMg(e.target.value)}/>
          <NumInput label="Desired Dose (mcg)" placeholder="e.g. 250" value={desiredMcg} onChange={e=>setDesiredMcg(e.target.value)}/>
        </div>
        <div style={{marginTop:12}}><BacStepper value={bacWaterMl} onChange={setBacWaterMl}/></div>
        <div style={{marginTop:12}}><NumInput label="Syringe Size (IU)" placeholder="100" value={syringeIU} onChange={e=>setSyringeIU(e.target.value)}/></div>
        <Btn style={{width:"100%",justifyContent:"center",marginTop:16}} icon="flask" onClick={calculate}>Calculate</Btn>
      </Card>
      {result && (
        <Card style={{borderColor:`${T.accent}44`}}>
          <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:12}}>
            <Icon name="check" size={15} color={T.green}/>
            <span style={{fontSize:11,fontWeight:700,color:T.green,textTransform:"uppercase",letterSpacing:.8}}>Results</span>
          </div>
          {[{label:"Concentration",val:`${result.mcgPerMl.toFixed(0)} mcg / mL`},{label:"Volume to draw",val:`${result.mlNeeded.toFixed(3)} mL`}].map(r=>(
            <div key={r.label} style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:`1px solid ${T.border}`}}>
              <span style={{fontSize:14,color:T.textSub}}>{r.label}</span>
              <span style={{fontSize:15,fontWeight:600,color:T.text}}>{r.val}</span>
            </div>
          ))}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",padding:"14px 0 8px"}}>
            <span style={{fontSize:14,color:T.textSub}}>Draw to</span>
            <span style={{fontSize:34,fontWeight:900,color:T.accent,letterSpacing:-1.5}}>{result.iuNeeded.toFixed(1)}<span style={{fontSize:16,fontWeight:500,color:T.textSub,marginLeft:5}}>IU</span></span>
          </div>
          <div style={{background:T.accentDim,borderRadius:10,padding:"11px 14px"}}>
            <p style={{fontSize:13,color:T.text,margin:0}}>Draw to <strong style={{color:T.accent}}>{result.iuNeeded.toFixed(1)} IU</strong> on a {syringeIU}-IU syringe for exactly <strong>{desiredMcg} mcg</strong>.</p>
          </div>
        </Card>
      )}
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════
// INVENTORY
// ══════════════════════════════════════════════════════════════════════════
const StatusTag = ({status}) => {
  const isPowder = !status || status === "powder";
  return (
    <span style={{
      fontSize:10, fontWeight:800, letterSpacing:.8, textTransform:"uppercase",
      padding:"2px 7px", borderRadius:6,
      background: isPowder ? "rgba(180,180,180,.15)" : "rgba(255,214,10,.15)",
      color:       isPowder ? "#aaa"                  : "#ffd60a",
      border:      isPowder ? "1px solid rgba(180,180,180,.2)" : "1px solid rgba(255,214,10,.25)",
    }}>
      {isPowder ? "Powder Only" : "Reconstituted"}
    </span>
  );
};

const Inventory = ({vials,addVial,updateVial,deleteVial,reorderVials}) => {
  const [modal,  setModal]  = useState(false);
  const [editId, setEditId] = useState(null);
  const [saving, setSaving] = useState(false);
  const EMPTY = {name:"",totalMg:"",remaining:"",dot:"",shape:"circle",status:"powder",bacWaterMl:"",standardDoseIu:"10",doseUnit:"mcg",doseAmount:"",costPaid:"",notes:""};
  const [form, setForm]     = useState(EMPTY);
  const [saveError, setSaveError] = useState("");

  const save = async () => {
    if(!form.name||!form.totalMg) return;
    setSaving(true); setSaveError("");
    if(editId){
      await updateVial(editId,form);
      setSaving(false); setModal(false); setEditId(null); setForm(EMPTY);
    } else {
      const result = await addVial(form);
      setSaving(false);
      if(result?.error){
        setSaveError(result.error.message + " [" + result.error.code + "]");
      } else {
        setModal(false); setEditId(null); setForm(EMPTY); setSaveError("");
      }
    }
  };

  const openEdit = (v) => {
    setForm({
      name:v.name, totalMg:v.total_mg, remaining:v.remaining_mg,
      dot:v.dot||"", shape:v.shape||"circle",
      status:v.status||"powder", bacWaterMl:v.bac_water_ml||"",
      standardDoseIu:v.standard_dose_iu||"10", doseUnit:v.dose_unit||"mcg", doseAmount:"", costPaid:v.cost_paid||"",
      notes:v.notes||"",
    });
    setEditId(v.id); setModal(true);
  };

  const pct = (v) => Math.max(0,Math.min(100,Math.round((v.remaining_mg/v.total_mg)*100)));

  // Dose info for reconstituted vials
  const doseInfo = (v) => {
    if(v.status !== "reconstituted" || !v.bac_water_ml || !v.total_mg || !v.standard_dose_iu) return null;
    const mcgPerMl       = (v.total_mg * 1000) / v.bac_water_ml;           // mcg per mL
    const mlPerDose      = v.standard_dose_iu / 100;                        // mL per dose (100 IU syringe)
    const doseAmountMcg  = mcgPerMl * mlPerDose;                            // mcg per dose
    const doseAmountMg   = doseAmountMcg / 1000;
    const totalDoses     = (v.total_mg * 1000) / doseAmountMcg;
    const remainingDoses = (v.remaining_mg * 1000) / doseAmountMcg;
    return {
      doseAmountMcg, doseAmountMg, totalDoses, remainingDoses,
      unit: v.dose_unit || "mcg",
      stdIu: v.standard_dose_iu,
    };
  };

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:13,color:T.textSub}}>{vials.length} vial{vials.length!==1?"s":""} tracked</span>
        <Btn icon="plus" onClick={()=>{setEditId(null);setForm(EMPTY);setModal(true);}}>Add Vial</Btn>
      </div>

      {vials.length===0 && (
        <Card style={{textAlign:"center",padding:52}}>
          <Icon name="box" size={40} color={T.textMute}/>
          <p style={{color:T.textSub,marginTop:12,fontSize:14}}>No vials yet. Add your first one.</p>
        </Card>
      )}

      {/* ── Drag state ── */}
      {[
        { key:"reconstituted", label:"Active / Reconstituted", accent:T.amber,  icon:"💉" },
        { key:"powder",        label:"Storage / Powder Only",  accent:T.textSub, icon:"🧪" },
      ].map(folder => {
        const group = vials.filter(v=>(v.status||"powder")===folder.key);
        if(group.length===0) return null;

        // ── per-folder drag handlers ──────────────────────────────────────
        const handleDragStart = (e, id) => {
          e.dataTransfer.effectAllowed = "move";
          e.dataTransfer.setData("vialId", id);
          e.dataTransfer.setData("folderKey", folder.key);
        };
        const handleDragOver = (e) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
        const handleDrop = (e, targetId) => {
          e.preventDefault();
          const draggedId  = e.dataTransfer.getData("vialId");
          const fromFolder = e.dataTransfer.getData("folderKey");
          if(draggedId === targetId || fromFolder !== folder.key) return;
          const idx  = group.findIndex(v=>v.id===draggedId);
          const tIdx = group.findIndex(v=>v.id===targetId);
          if(idx<0||tIdx<0) return;
          const reordered = [...group];
          const [moved] = reordered.splice(idx,1);
          reordered.splice(tIdx,0,moved);
          reorderVials(reordered);
        };

        return (
          <div key={folder.key} style={{display:"flex",flexDirection:"column",gap:10}}>
            {/* Folder header */}
            <div style={{display:"flex",alignItems:"center",gap:8,paddingLeft:2}}>
              <span style={{fontSize:13}}>{folder.icon}</span>
              <span style={{fontSize:11,fontWeight:800,color:folder.accent,textTransform:"uppercase",letterSpacing:.8}}>{folder.label}</span>
              <span style={{fontSize:11,color:T.textMute}}>({group.length})</span>
              {group.length>1 && <span style={{fontSize:10,color:T.textMute,marginLeft:4}}>· drag to reorder</span>}
            </div>

            {group.map(v=>{
        const p    = pct(v);
        const barColor = p<25?T.red:p<50?T.amber:T.green;
        const dotColor = v.dot==="rainbow" ? "#bf5af2" : (v.dot||T.accent);
        const di   = doseInfo(v);
        const remDoses = di ? Math.floor(di.remainingDoses) : null;
        const totDoses = di ? Math.round(di.totalDoses)     : null;
        const doseLabel = di
          ? (di.unit==="mcg" ? di.doseAmountMcg.toFixed(1)+" mcg" : di.doseAmountMg.toFixed(3)+" mg")
          : null;
        const pctDoses = totDoses ? Math.round((remDoses/totDoses)*100) : p;

        return (
          <div key={v.id}
            draggable
            onDragStart={e=>handleDragStart(e,v.id)}
            onDragOver={handleDragOver}
            onDrop={e=>handleDrop(e,v.id)}
            style={{cursor:"grab",borderRadius:16}}>
          <Card style={{borderLeft:`3px solid ${dotColor}`,cursor:"inherit"}}>
            {/* Header row */}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  {/* Drag handle */}
                  <span style={{color:T.textMute,fontSize:14,cursor:"grab",userSelect:"none",marginRight:-2}} title="Drag to reorder">⠿</span>
                  {v.dot && <DotIcon dot={v.dot} shape={v.shape||"circle"} size={9}/>}
                  <span style={{fontSize:17,fontWeight:800,color:T.text}}>{v.name}</span>
                  <StatusTag status={v.status}/>
                  {(di?pctDoses:p)<25 && <Badge bg={T.redDim} color={T.red}>Low Supply</Badge>}
                </div>
                <span style={{fontSize:13,color:T.textSub}}>{v.total_mg} mg total · added {fmtDate(v.created_at)}</span>
                {v.bac_water_ml && <span style={{fontSize:12,color:T.textMute}}> · {v.bac_water_ml} mL BAC water</span>}
              </div>
              <div style={{display:"flex",gap:6,marginLeft:8}}>
                <button onClick={()=>openEdit(v)} style={{background:T.elevated,border:"none",borderRadius:8,padding:"7px 9px",cursor:"pointer"}}><Icon name="edit" size={15} color={T.textSub}/></button>
                <button onClick={()=>deleteVial(v.id)} style={{background:T.redDim,border:"none",borderRadius:8,padding:"7px 9px",cursor:"pointer"}}><Icon name="trash" size={15} color={T.red}/></button>
              </div>
            </div>

            {/* Progress — dose-based for reconstituted, mg-based for powder */}
            <div style={{marginTop:14}}>
              {di ? (
                <>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                    <span style={{fontSize:13,color:T.textSub}}>Remaining</span>
                    <span style={{fontSize:13,fontWeight:700,color:barColor}}>
                      {v.remaining_mg} mg · <span style={{color:barColor}}>{remDoses} of {totDoses} doses</span>
                    </span>
                  </div>
                  <div style={{height:5,background:T.elevated,borderRadius:99}}>
                    <div style={{height:5,borderRadius:99,width:`${Math.max(0,Math.min(100,(remDoses/totDoses)*100))}%`,background:barColor,transition:"width .5s ease"}}/>
                  </div>
                  <div style={{marginTop:8,display:"flex",gap:6}}>
                    <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"7px 0",textAlign:"center"}}>
                      <div style={{fontSize:14,fontWeight:700,color:T.text}}>{doseLabel}</div>
                      <div style={{fontSize:10,color:T.textMute,marginTop:1}}>per {di.stdIu} IU</div>
                    </div>
                    <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"7px 0",textAlign:"center"}}>
                      <div style={{fontSize:14,fontWeight:700,color:barColor}}>{remDoses}</div>
                      <div style={{fontSize:10,color:T.textMute,marginTop:1}}>doses left</div>
                    </div>
                    <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"7px 0",textAlign:"center"}}>
                      <div style={{fontSize:14,fontWeight:700,color:T.textSub}}>{totDoses}</div>
                      <div style={{fontSize:10,color:T.textMute,marginTop:1}}>total doses</div>
                    </div>
                  </div>
                </>
              ) : (
                <>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                    <span style={{fontSize:13,color:T.textSub}}>Remaining</span>
                    <span style={{fontSize:13,fontWeight:700,color:barColor}}>{v.remaining_mg} mg ({p}%)</span>
                  </div>
                  <div style={{height:5,background:T.elevated,borderRadius:99}}>
                    <div style={{height:5,borderRadius:99,width:`${p}%`,background:barColor,transition:"width .5s ease"}}/>
                  </div>
                </>
              )}
            </div>

            {v.notes && <p style={{marginTop:10,fontSize:13,color:T.textSub,marginBottom:0}}>{v.notes}</p>}
          </Card>
          </div>
        );
      })}
          </div>
        );
      })}

      <Modal open={modal} onClose={()=>{setModal(false);setSaveError("");}} title={editId?"Edit Vial":"Add Vial"}>
        <div style={{display:"flex",flexDirection:"column",gap:16}}>

          {/* ── Quick Add presets ── */}
          {!editId && (
            <div>
              <label style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.6,textTransform:"uppercase"}}>Quick Add</label>
              <div style={{display:"flex",flexDirection:"column",gap:6,marginTop:8}}>
                {PRESETS.map(p=>(
                  <button key={p.name}
                    onClick={()=>setForm(f=>({...f,name:p.name,totalMg:p.totalMg,dot:p.dot,shape:p.shape||"circle"}))}
                    style={{display:"flex",alignItems:"center",gap:10,background:form.name===p.name?T.accentDim:T.elevated,border:`1.5px solid ${form.name===p.name?T.accent:T.border}`,borderRadius:10,padding:"9px 14px",cursor:"pointer",transition:"all .15s",textAlign:"left"}}>
                    <DotIcon dot={p.dot} shape={p.shape||"circle"} size={10}/>
                    <span style={{fontSize:14,fontWeight:600,color:T.text,flex:1}}>{p.name}</span>
                    <span style={{fontSize:12,color:T.textSub}}>{p.totalMg} {p.unit}</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          <div style={{height:1,background:T.border}}/>

          {/* ── Dot color — compact row ── */}
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <label style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.6,textTransform:"uppercase",flexShrink:0}}>Color</label>
            <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
              {[
                {dot:"#4caf72",shape:"circle"},{dot:"#1a7a3c",shape:"circle"},
                {dot:"#2255cc",shape:"circle"},{dot:"#e07020",shape:"circle"},
                {dot:"#e03030",shape:"circle"},{dot:"#e0c020",shape:"circle"},
                {dot:"#888888",shape:"diamond"},{dot:"#e8e8e8",shape:"circle"},
                {dot:"rainbow",shape:"square"},{dot:"#4f9eff",shape:"circle"},
                {dot:"#bf5af2",shape:"circle"},
              ].map(opt=>(
                <button key={opt.dot} onClick={()=>setForm(f=>({...f,dot:opt.dot,shape:opt.shape}))}
                  style={{width:22,height:22,padding:0,border:form.dot===opt.dot?"2.5px solid #fff":"2.5px solid transparent",borderRadius:4,cursor:"pointer",background:"none",display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <DotIcon dot={opt.dot} shape={opt.shape} size={14}/>
                </button>
              ))}
              <input type="color" value={form.dot&&form.dot!=="rainbow"?form.dot:"#4f9eff"}
                onChange={e=>setForm(f=>({...f,dot:e.target.value,shape:"circle"}))}
                style={{width:22,height:22,padding:0,border:"none",borderRadius:4,cursor:"pointer",background:"transparent"}} title="Custom"/>
            </div>
          </div>

          {/* ── Name + total mg ── */}
          <Input label="Peptide Name" placeholder="e.g. BPC-157" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))}/>
          <NumInput label="Total (mg)" placeholder="10" value={form.totalMg} onChange={e=>setForm(f=>({...f,totalMg:e.target.value}))}/>
          {editId && <NumInput label="Remaining (mg)" placeholder="10" value={form.remaining} onChange={e=>setForm(f=>({...f,remaining:e.target.value}))}/>}

          {/* ── Status toggle ── */}
          <div>
            <label style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.6,textTransform:"uppercase"}}>Vial Status</label>
            <div style={{display:"flex",gap:8,marginTop:8}}>
              {["powder","reconstituted"].map(s=>(
                <button key={s} onClick={()=>setForm(f=>({...f,status:s}))}
                  style={{flex:1,padding:"10px",borderRadius:10,border:`1.5px solid ${form.status===s?(s==="powder"?"#888":T.amber):T.border}`,background:form.status===s?(s==="powder"?"rgba(180,180,180,.12)":"rgba(255,214,10,.1)"):"transparent",cursor:"pointer",transition:"all .15s"}}>
                  <div style={{fontSize:13,fontWeight:700,color:form.status===s?(s==="powder"?"#ccc":T.amber):T.textSub,textTransform:"uppercase",letterSpacing:.5}}>
                    {s==="powder"?"Powder Only":"Reconstituted"}
                  </div>
                </button>
              ))}
            </div>
          </div>

          {/* ── Reconstitution section ── */}
          {form.status==="reconstituted" && (() => {
            const mg    = parseFloat(form.totalMg) || 0;
            const iu    = parseFloat(form.standardDoseIu) || 0;
            const isDeg = form.doseUnit === "mg";
            // back-calculate BAC water needed so that stdDose IU = desired amount
            // concentration = (mg * 1000) / bacMl  =>  bacMl = (mg * 1000) / (doseAmt / (iu/100))
            // doseAmt in mcg, iu/100 = mL
            // => bacMl = (mg * 1000 * iu/100) / doseAmt
            // But we want user to set the dose amount and we show them the required BAC water.
            // So: bacMl = (mg * 1000) / (doseAmtMcg / (iu/100))
            //           = (mg * 1000 * iu) / (doseAmtMcg * 100)
            const doseAmtMcg = isDeg
              ? (parseFloat(form.doseAmount)||0) * 1000
              : (parseFloat(form.doseAmount)||0);
            const mlPerDose  = iu / 100;
            const bacNeeded  = (doseAmtMcg > 0 && mlPerDose > 0)
              ? (mg * 1000 * mlPerDose) / doseAmtMcg
              : null;

            return (
              <div style={{background:T.elevated,borderRadius:12,padding:"14px",display:"flex",flexDirection:"column",gap:12,border:`1px solid ${T.border}`}}>
                <label style={{fontSize:11,fontWeight:700,color:T.amber,letterSpacing:.6,textTransform:"uppercase"}}>Reconstitution Setup</label>

                {/* Standard dose in IU + unit toggle */}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                  <NumInput label="Standard Dose (IU)" placeholder="10" value={form.standardDoseIu}
                    onChange={e=>setForm(f=>({...f,standardDoseIu:e.target.value}))}/>
                  <div style={{display:"flex",flexDirection:"column",gap:5}}>
                    <label style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.6,textTransform:"uppercase"}}>Display As</label>
                    <div style={{display:"flex",height:42,borderRadius:10,overflow:"hidden",border:`1.5px solid ${T.border}`}}>
                      {["mcg","mg"].map(u=>(
                        <button key={u} onClick={()=>setForm(f=>({...f,doseUnit:u}))}
                          style={{flex:1,border:"none",cursor:"pointer",fontSize:14,fontWeight:700,
                            background:form.doseUnit===u?T.accent:"transparent",
                            color:form.doseUnit===u?"#fff":T.textSub,transition:"all .15s"}}>
                          {u}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Desired dose amount */}
                <NumInput
                  label={`Desired Dose Amount (${form.doseUnit})`}
                  placeholder={form.doseUnit==="mcg"?"e.g. 250":"e.g. 0.25"}
                  value={form.doseAmount||""}
                  onChange={e=>setForm(f=>({...f,doseAmount:e.target.value}))}/>

                {/* Live BAC water result */}
                {bacNeeded !== null && bacNeeded > 0 ? (
                  <div style={{background:"rgba(255,214,10,.08)",borderRadius:10,padding:"12px 14px",border:"1px solid rgba(255,214,10,.2)"}}>
                    <div style={{fontSize:11,fontWeight:700,color:T.amber,letterSpacing:.6,textTransform:"uppercase",marginBottom:6}}>Add this much BAC water</div>
                    <div style={{fontSize:28,fontWeight:900,color:T.amber,letterSpacing:-1}}>{bacNeeded.toFixed(2)} <span style={{fontSize:15,fontWeight:500,color:T.textSub}}>mL</span></div>
                    <div style={{fontSize:12,color:T.textSub,marginTop:4}}>
                      Every {iu} IU draw = {isDeg ? ((doseAmtMcg/1000).toFixed(3)+" mg") : (doseAmtMcg.toFixed(1)+" mcg")}
                    </div>
                  </div>
                ) : (
                  <div style={{fontSize:12,color:T.textMute,textAlign:"center"}}>
                    Enter your standard dose and desired amount above to see the required BAC water.
                  </div>
                )}

                {/* Store the BAC water value for inventory display */}
                {bacNeeded !== null && bacNeeded > 0 && form.bacWaterMl !== bacNeeded.toFixed(2) &&
                  (() => { setTimeout(()=>setForm(f=>({...f,bacWaterMl:bacNeeded.toFixed(2)})),0); return null; })()
                }
              </div>
            );
          })()}

          <NumInput label="Cost Paid (optional, $)" placeholder="e.g. 45.00" value={form.costPaid} onChange={e=>setForm(f=>({...f,costPaid:e.target.value}))}/>
          <Input label="Notes (optional)" placeholder="Storage, source, batch…" value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/>

          {saveError && (
            <div style={{background:T.redDim,border:`1px solid ${T.red}55`,borderRadius:10,padding:"10px 14px",display:"flex",gap:8,alignItems:"flex-start"}}>
              <Icon name="alert" size={15} color={T.red}/>
              <div>
                <div style={{fontSize:13,fontWeight:700,color:T.red,marginBottom:2}}>Failed to save vial</div>
                <div style={{fontSize:12,color:T.red,opacity:.85,fontFamily:"monospace"}}>{saveError}</div>
              </div>
            </div>
          )}
          <Btn loading={saving} style={{width:"100%",justifyContent:"center"}} icon="check" onClick={save}>{editId?"Save Changes":"Add Vial"}</Btn>
        </div>
      </Modal>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════
// CALENDAR
// ══════════════════════════════════════════════════════════════════════════
const Calendar = ({vials, entries}) => {
  // weekOffset: 0 = current week, -1 = last week, etc.
  const [weekOffset,  setWeekOffset]  = useState(0);
  const [selectedDay, setSelectedDay] = useState(null); // "YYYY-MM-DD"
  const [dayModal,    setDayModal]    = useState(false);

  // ── Date helpers ─────────────────────────────────────────────────────────
  const toYMD = (d) => {
    const pad = n => String(n).padStart(2,"0");
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
  };
  const parseYMD = (s) => {
    const [y,m,d] = s.split("-").map(Number);
    return new Date(y, m-1, d);
  };
  const addDays = (d, n) => { const r = new Date(d); r.setDate(r.getDate()+n); return r; };

  // Sunday of the displayed week
  const today    = new Date();
  const todayYMD = toYMD(today);
  const dow      = today.getDay(); // 0=Sun
  const weekStart = addDays(today, -dow + weekOffset*7);
  const weekDays  = Array.from({length:7}, (_,i) => addDays(weekStart, i));
  const weekEnd   = weekDays[6];

  const mmdd = (d) => d.toLocaleDateString("en-US",{month:"short",day:"numeric"});
  const weekLabel = `Week of ${mmdd(weekStart)} – ${mmdd(weekEnd)}`;

  // ── Build day→entries lookup ──────────────────────────────────────────
  const byDay = {};
  entries.forEach(e => {
    const d = toYMD(new Date(e.injected_at));
    if(!byDay[d]) byDay[d] = [];
    byDay[d].push(e);
  });

  // ── Entries for selected day modal ───────────────────────────────────
  const dayEntries = selectedDay ? (byDay[selectedDay]||[]) : [];

  // ── 7-day summary (Sun–Sat of displayed week) ─────────────────────────
  const weekStartYMD = toYMD(weekStart);
  const weekEndYMD   = toYMD(weekEnd);

  // Entries within the displayed week
  const weekEntries = entries.filter(e => {
    const d = toYMD(new Date(e.injected_at));
    return d >= weekStartYMD && d <= weekEndYMD;
  });

  // Group by vial_id for summary
  const vialSummary = {};
  weekEntries.forEach(e => {
    const key = e.vial_id || e.vial_name;
    if(!vialSummary[key]) vialSummary[key] = {
      name: e.vial_name, dot: e.vial_dot, days: new Set(), totalMcg: 0,
    };
    vialSummary[key].days.add(toYMD(new Date(e.injected_at)));
    vialSummary[key].totalMcg += +(e.dose_mcg || 0);
  });

  // Streak = consecutive days ending today (or most recent day in view)
  const calcStreak = (vialId) => {
    const vialEntries = entries
      .filter(e => (e.vial_id||e.vial_name) === vialId)
      .map(e => toYMD(new Date(e.injected_at)));
    const daySet = new Set(vialEntries);
    let streak = 0;
    let check  = new Date(today);
    while(true) {
      if(daySet.has(toYMD(check))) { streak++; check = addDays(check,-1); }
      else break;
    }
    return streak;
  };

  const DAY_LABELS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

  return (
    <div style={{display:"flex",flexDirection:"column",gap:14}}>

      {/* ── Week nav ── */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8}}>
        <button onClick={()=>setWeekOffset(w=>w-1)}
          style={{width:36,height:36,borderRadius:10,border:`1px solid ${T.border}`,background:T.elevated,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
          <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke={T.text} strokeWidth={2.2} strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
        </button>
        <span style={{fontSize:13,fontWeight:700,color:T.text,textAlign:"center",flex:1}}>{weekLabel}</span>
        <button onClick={()=>setWeekOffset(w=>Math.min(0,w+1))}
          style={{width:36,height:36,borderRadius:10,border:`1px solid ${T.border}`,background:T.elevated,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,opacity:weekOffset>=0?0.3:1}}
          disabled={weekOffset>=0}>
          <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke={T.text} strokeWidth={2.2} strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
        </button>
      </div>

      {/* ── 7-day grid ── */}
      <Card style={{padding:"14px 10px"}}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:4}}>
          {weekDays.map((day,i) => {
            const ymd      = toYMD(day);
            const isToday  = ymd === todayYMD;
            const dayLogs  = byDay[ymd] || [];
            const selected = selectedDay === ymd;
            // deduplicate dots by vial_id
            const dots = [];
            const seen = new Set();
            dayLogs.forEach(e => {
              const k = e.vial_id||e.vial_name;
              if(!seen.has(k)) { seen.add(k); dots.push({dot:e.vial_dot, shape:"circle"}); }
            });

            return (
              <button key={ymd} onClick={()=>{setSelectedDay(ymd);setDayModal(true);}}
                style={{display:"flex",flexDirection:"column",alignItems:"center",gap:3,padding:"8px 2px",borderRadius:10,border:`1.5px solid ${selected?T.accent:isToday?"rgba(79,158,255,.4)":"transparent"}`,background:selected?T.accentDim:isToday?"rgba(79,158,255,.07)":"transparent",cursor:"pointer",minWidth:0}}>
                <span style={{fontSize:10,fontWeight:700,color:T.textSub,letterSpacing:.3}}>{DAY_LABELS[i]}</span>
                <span style={{fontSize:16,fontWeight:isToday?900:600,color:isToday?T.accent:T.text}}>{day.getDate()}</span>
                {/* Dot cluster */}
                <div style={{display:"flex",flexWrap:"wrap",justifyContent:"center",gap:2,minHeight:14,marginTop:2}}>
                  {dots.slice(0,4).map((d,di)=>(
                    <DotIcon key={di} dot={d.dot||T.accent} shape="circle" size={7}/>
                  ))}
                  {dots.length > 4 && <span style={{fontSize:8,color:T.textSub}}>+{dots.length-4}</span>}
                </div>
              </button>
            );
          })}
        </div>
      </Card>

      {/* ── Weekly summary by peptide ── */}
      {Object.keys(vialSummary).length > 0 ? (
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          <div style={{fontSize:11,fontWeight:700,color:T.textSub,textTransform:"uppercase",letterSpacing:.7,paddingLeft:2}}>
            This Week's Activity
          </div>
          {Object.entries(vialSummary).map(([key, s]) => {
            const streak = calcStreak(key);
            const totalMg = s.totalMcg / 1000;
            const doseLabel = totalMg >= 1
              ? `${totalMg.toFixed(2)} mg`
              : `${s.totalMcg.toFixed(1)} mcg`;

            return (
              <Card key={key} style={{padding:"12px 16px"}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <DotIcon dot={s.dot||T.accent} shape="circle" size={10}/>
                  <span style={{fontSize:15,fontWeight:800,color:T.text,flex:1}}>{s.name}</span>
                </div>
                <div style={{display:"flex",gap:8,marginTop:10}}>
                  <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"8px 0",textAlign:"center"}}>
                    <div style={{fontSize:14,fontWeight:700,color:T.text}}>{doseLabel}</div>
                    <div style={{fontSize:10,color:T.textSub,marginTop:2}}>consumed this week</div>
                  </div>
                  <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"8px 0",textAlign:"center"}}>
                    <div style={{fontSize:14,fontWeight:700,color:streak>=5?T.green:streak>=3?T.amber:T.text}}>
                      {streak} {streak===1?"day":"days"}
                    </div>
                    <div style={{fontSize:10,color:T.textSub,marginTop:2}}>
                      {streak>=2?"🔥 streak":"current streak"}
                    </div>
                  </div>
                  <div style={{flex:1,background:T.elevated,borderRadius:8,padding:"8px 0",textAlign:"center"}}>
                    <div style={{fontSize:14,fontWeight:700,color:T.accent}}>{s.days.size}</div>
                    <div style={{fontSize:10,color:T.textSub,marginTop:2}}>days taken</div>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      ) : (
        <Card style={{textAlign:"center",padding:36}}>
          <p style={{color:T.textSub,margin:0,fontSize:14}}>No injections logged this week.</p>
        </Card>
      )}

      {/* ── Day detail modal ── */}
      <Modal open={dayModal} onClose={()=>setDayModal(false)}
        title={selectedDay ? new Date(selectedDay+"T12:00:00").toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric"}) : ""}>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {dayEntries.length === 0 ? (
            <p style={{color:T.textSub,textAlign:"center",padding:"20px 0",margin:0}}>No injections logged on this day.</p>
          ) : dayEntries.map(e => (
            <div key={e.id} style={{display:"flex",alignItems:"center",gap:12,background:T.elevated,borderRadius:10,padding:"12px 14px"}}>
              <div style={{width:34,height:34,borderRadius:9,background:e.vial_dot?`${e.vial_dot}22`:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,border:`1.5px solid ${e.vial_dot||T.accent}44`}}>
                {e.vial_dot ? <DotIcon dot={e.vial_dot} shape="circle" size={14}/> : <Icon name="syringe" size={15} color={T.accent}/>}
              </div>
              <div style={{flex:1}}>
                <div style={{fontSize:15,fontWeight:800,color:T.text}}>{e.vial_name}</div>
                <div style={{fontSize:13,color:T.textSub}}>
                  {e.dose_iu && <span style={{color:T.accent}}>{e.dose_iu} IU</span>}
                  {e.dose_mcg && <span style={{color:T.text}}> · {+e.dose_mcg >= 1000 ? (+e.dose_mcg/1000).toFixed(2)+" mg" : (+e.dose_mcg).toFixed(1)+" mcg"}</span>}
                </div>
                {e.notes && <div style={{fontSize:12,color:T.textSub,marginTop:2}}>{e.notes}</div>}
              </div>
              <div style={{fontSize:11,color:T.textMute,flexShrink:0}}>
                {new Date(e.injected_at).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"})}
              </div>
            </div>
          ))}
        </div>
      </Modal>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════
// LOG
// ══════════════════════════════════════════════════════════════════════════
const Log = ({vials,entries,addEntry,deleteEntry,deductVial}) => {
  const [modal,  setModal]  = useState(false);
  const [saving, setSaving] = useState(false);
  // local datetime string for datetime-local inputs (uses user's device timezone)
const localNow = () => {
  const d = new Date();
  const pad = n => String(n).padStart(2,"0");
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
};
const EMPTY = {vialId:"",doseMcg:"",doseIU:"10",doseML:"",timestamp:localNow(),notes:""};
  const [form, setForm] = useState(EMPTY);

  const logEntry = async () => {
    if(!form.vialId||!form.doseIU) return;
    setSaving(true);
    const vial = vials.find(v=>v.id===form.vialId);
    // Compute mcg from IU using vial's reconstitution config
    let computedMcg = null;
    let computedMl  = null;
    if(vial?.bac_water_ml && vial?.total_mg){
      const mcgPerMl = (vial.total_mg*1000)/vial.bac_water_ml;
      computedMl  = Number(form.doseIU)/100;
      computedMcg = mcgPerMl * computedMl;
    }
    const deductMg = computedMcg ? computedMcg/1000 : 0;
    if(vial && deductMg) await deductVial(vial.id, deductMg);
    await addEntry({
      ...form,
      doseMcg: computedMcg ? computedMcg.toFixed(2) : null,
      doseML:  computedMl  ? computedMl.toFixed(3)  : null,
      vialName:vial?.name||"Unknown",
      vialDot: vial?.dot||"",
    });
    setSaving(false); setModal(false); setForm({...EMPTY,timestamp:localNow()});
  };

  const grouped = entries.reduce((acc,e)=>{
    const day = new Date(e.injected_at).toDateString();
    if(!acc[day]) acc[day]=[];
    acc[day].push(e); return acc;
  },{});

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:13,color:T.textSub}}>{entries.length} injection{entries.length!==1?"s":""} logged</span>
        <Btn icon="plus" onClick={()=>{setForm({...EMPTY,timestamp:localNow()});setModal(true);}}>Log Injection</Btn>
      </div>

      {entries.length===0 && (
        <Card style={{textAlign:"center",padding:52}}>
          <Icon name="clock" size={40} color={T.textMute}/>
          <p style={{color:T.textSub,marginTop:12,fontSize:14}}>No injections logged yet.</p>
        </Card>
      )}

      {Object.entries(grouped).map(([day,dayEntries])=>(
        <div key={day}>
          <div style={{fontSize:11,fontWeight:700,color:T.textMute,textTransform:"uppercase",letterSpacing:.8,marginBottom:8,paddingLeft:2}}>{day}</div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {dayEntries.map(e=>(
              <Card key={e.id} style={{padding:"14px 16px"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12}}>
                    <div style={{width:38,height:38,borderRadius:11,background:e.vial_dot?`${e.vial_dot}22`:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,border:`1.5px solid ${e.vial_dot||T.accent}44`}}>
                      {e.vial_dot ? <span style={{width:14,height:14,borderRadius:"50%",background:e.vial_dot}}/> : <Icon name="syringe" size={17} color={T.accent}/>}
                    </div>
                    <div>
                      <div style={{fontSize:15,fontWeight:800,color:T.text}}>{e.vial_name}</div>
                      <div style={{fontSize:13}}>
                        <span style={{color:T.text}}>{e.dose_mcg} mcg</span>
                        {e.dose_iu ? <span style={{color:T.accent}}> · {e.dose_iu} IU</span> : ""}
                        {e.dose_ml ? <span style={{color:T.textSub}}> · {e.dose_ml} mL</span> : ""}
                      </div>
                    </div>
                  </div>
                  <div style={{textAlign:"right",display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6}}>
                    <div style={{fontSize:12,color:T.textMute}}>{fmt(e.injected_at)}</div>
                    <button onClick={()=>deleteEntry(e.id)} style={{background:"none",border:"none",cursor:"pointer",padding:0}}><Icon name="trash" size={14} color={T.textMute}/></button>
                  </div>
                </div>
                {e.notes && <p style={{marginTop:8,fontSize:13,color:T.textSub,paddingLeft:50,marginBottom:0}}>{e.notes}</p>}
              </Card>
            ))}
          </div>
        </div>
      ))}

      <Modal open={modal} onClose={()=>setModal(false)} title="Log Injection">
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          {/* Only reconstituted vials can be injected */}
          <Sel label="Peptide" value={form.vialId} onChange={e=>setForm(f=>({...f,vialId:e.target.value}))}
            options={[{value:"",label:"Select vial…"},...vials
              .filter(v=>v.status==="reconstituted")
              .map(v=>({value:v.id,label:`${v.name} (${v.remaining_mg} mg left)`}))
            ]}/>
          {vials.filter(v=>v.status==="reconstituted").length===0 && (
            <div style={{background:"rgba(255,214,10,.08)",border:"1px solid rgba(255,214,10,.25)",borderRadius:10,padding:"10px 14px"}}>
              <span style={{fontSize:13,color:T.tip}}>⚠ No reconstituted vials yet. Reconstitute a vial in Inventory before logging an injection.</span>
            </div>
          )}

          {/* IU stepper — only input needed */}
          <div style={{background:T.elevated,borderRadius:14,padding:"14px 14px 16px",border:`1px solid ${T.border}`}}>
            <label style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.6,textTransform:"uppercase"}}>Units to Draw</label>
            <div style={{textAlign:"center",margin:"10px 0 14px"}}>
              <span style={{fontSize:48,fontWeight:900,color:T.accent,letterSpacing:-2,lineHeight:1}}>{form.doseIU||0}</span>
              <span style={{fontSize:16,fontWeight:500,color:T.textSub,marginLeft:6}}>IU</span>
              {/* Computed dose from vial config */}
              {(()=>{
                const vial = vials.find(v=>v.id===form.vialId);
                const iu   = Number(form.doseIU||0);
                if(!vial||!vial.bac_water_ml||!vial.total_mg||!iu) return null;
                const mcgPerMl  = (vial.total_mg*1000)/vial.bac_water_ml;
                const mlPerDose = iu/100;
                const doseAmt   = mcgPerMl*mlPerDose;
                const unit      = vial.dose_unit||"mcg";
                const display   = unit==="mg" ? (doseAmt/1000).toFixed(3)+" mg" : doseAmt.toFixed(1)+" mcg";
                return (
                  <div style={{marginTop:4,fontSize:14,color:T.tip,fontWeight:600}}>= {display}</div>
                );
              })()}
            </div>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:8}}>
              <span style={{fontSize:11,fontWeight:700,color:T.textMute,width:24,textAlign:"right"}}>±1</span>
              <button onClick={()=>setForm(f=>({...f,doseIU:String(Math.max(0,Number(f.doseIU||0)-1))}))} style={{flex:1,height:42,borderRadius:10,border:`1px solid ${T.border}`,background:T.surface,color:T.text,fontSize:22,fontWeight:300,cursor:"pointer"}} onMouseDown={e=>e.currentTarget.style.transform="scale(.94)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"}>−</button>
              <button onClick={()=>setForm(f=>({...f,doseIU:String(Number(f.doseIU||0)+1)}))} style={{flex:1,height:42,borderRadius:10,border:`1px solid ${T.border}`,background:T.surface,color:T.text,fontSize:22,fontWeight:300,cursor:"pointer"}} onMouseDown={e=>e.currentTarget.style.transform="scale(.94)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"}>+</button>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}>
              <span style={{fontSize:11,fontWeight:700,color:T.textMute,width:24,textAlign:"right"}}>±5</span>
              <button onClick={()=>setForm(f=>({...f,doseIU:String(Math.max(0,Number(f.doseIU||0)-5))}))} style={{flex:1,height:42,borderRadius:10,border:`1px solid ${T.border}`,background:T.surface,color:T.accent,fontSize:15,fontWeight:700,cursor:"pointer"}} onMouseDown={e=>e.currentTarget.style.transform="scale(.94)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"}>−5</button>
              <button onClick={()=>setForm(f=>({...f,doseIU:String(Number(f.doseIU||0)+5)}))} style={{flex:1,height:42,borderRadius:10,border:`1px solid ${T.border}`,background:T.surface,color:T.accent,fontSize:15,fontWeight:700,cursor:"pointer"}} onMouseDown={e=>e.currentTarget.style.transform="scale(.94)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"}>+5</button>
            </div>
            <div style={{display:"flex",gap:8,justifyContent:"center"}}>
              {[10,20,25,50].map(n=>(
                <button key={n} onClick={()=>setForm(f=>({...f,doseIU:String(n)}))}
                  style={{padding:"5px 14px",borderRadius:20,border:`1.5px solid ${Number(form.doseIU)===n?T.accent:T.border}`,background:Number(form.doseIU)===n?T.accentDim:"transparent",color:Number(form.doseIU)===n?T.accent:T.textSub,fontSize:13,fontWeight:700,cursor:"pointer",transition:"all .15s"}}>
                  {n}
                </button>
              ))}
            </div>
          </div>

          <Input label="Date & Time" type="datetime-local" value={form.timestamp} onChange={e=>setForm(f=>({...f,timestamp:e.target.value}))}/>
          <Input label="Notes (optional)" placeholder="Site, how you felt, etc." value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/>
          <Btn loading={saving} style={{width:"100%",justifyContent:"center"}} icon="check" onClick={logEntry}>Log Injection</Btn>
        </div>
      </Modal>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════
// EXPORT + IMPORT MODAL
// ══════════════════════════════════════════════════════════════════════════
const DataModal = ({open,onClose,vials,entries,userId,onImportDone}) => {
  const [tab,        setTab]        = useState("export");
  const [exportDone, setExportDone] = useState(false);
  const [importing,  setImporting]  = useState(false);
  const [importMsg,  setImportMsg]  = useState(null); // {type:"success"|"error", text}
  const fileRef = React.useRef();

  // ── Export ───────────────────────────────────────────────────────────────
  const handleExport = () => {
    const ts = new Date().toISOString().slice(0,10);
    const vialsCSV = toCSV(
      ["ID","Name","Total (mg)","Remaining (mg)","% Left","Status","BAC Water (mL)","Standard Dose (IU)","Dose Unit","Cost Paid","Notes","Created"],
      vials.map(v=>[v.id,v.name,v.total_mg,v.remaining_mg,Math.round((v.remaining_mg/v.total_mg)*100),v.status||"powder",v.bac_water_ml||"",v.standard_dose_iu||"",v.dose_unit||"mcg",v.cost_paid||"",v.notes||"",fmtDate(v.created_at)])
    );
    const logCSV = toCSV(
      ["ID","Peptide","Dose (mcg)","IU","mL","Injected At","Notes"],
      entries.map(e=>[e.id,e.vial_name,e.dose_mcg||"",e.dose_iu||"",e.dose_ml||"",e.injected_at,e.notes||""])
    );
    const combined = [`PinPal Export — ${ts}`,"","=== INVENTORY ===",vialsCSV,"","=== INJECTION LOG ===",logCSV].join("\n");
    downloadCSV(`pinpal-export-${ts}.csv`,combined);
    setExportDone(true); setTimeout(()=>setExportDone(false),2000);
  };

  // ── Import ───────────────────────────────────────────────────────────────
  const parseCSVLine = (line) => {
    const result = []; let cur = ""; let inQ = false;
    for(let i=0;i<line.length;i++){
      const c = line[i];
      if(c==='"'){ if(inQ && line[i+1]==='"'){cur+='"';i++;}else{inQ=!inQ;} }
      else if(c===',' && !inQ){ result.push(cur); cur=""; }
      else cur+=c;
    }
    result.push(cur);
    return result;
  };

  const parseCSVBlock = (text) => {
    const lines = text.split("\n").map(l=>l.trim()).filter(l=>l.length>0);
    if(lines.length<2) return [];
    const headers = parseCSVLine(lines[0]).map(h=>h.trim().toLowerCase());
    return lines.slice(1).map(line=>{
      const vals = parseCSVLine(line);
      const obj = {};
      headers.forEach((h,i)=>{ obj[h] = vals[i]?.trim()||""; });
      return obj;
    });
  };

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    if(!file) return;
    setImporting(true); setImportMsg(null);
    try {
      const text = await file.text();

      // Split into sections
      const sections = {};
      let currentSection = null; const sectionLines = {};
      text.split("\n").forEach(line=>{
        const m = line.match(/^===\s*(.+?)\s*===$/);
        if(m){ currentSection = m[1].toUpperCase(); sectionLines[currentSection]=[]; }
        else if(currentSection) sectionLines[currentSection].push(line);
      });

      let vialsImported=0, logImported=0, errors=[];

      // ── Import Inventory ─────────────────────────────────────────────
      const invKey = Object.keys(sectionLines).find(k=>k.includes("INVENTOR"));
      if(invKey){
        const block = sectionLines[invKey].join("\n");
        const rows  = parseCSVBlock(block);
        for(const r of rows){
          const name = r["name"]||r["peptide name"];
          const totalMg = parseFloat(r["total (mg)"]||r["total_mg"]||r["total mg"]);
          if(!name || isNaN(totalMg)) continue;
          const remainingMg = parseFloat(r["remaining (mg)"]||r["remaining_mg"]||r["remaining mg"])||totalMg;
          const {error} = await supabase.from("vials").insert({
            user_id:userId,
            name, total_mg:totalMg, remaining_mg:remainingMg,
            status:r["status"]||"powder",
            bac_water_ml:parseFloat(r["bac water (ml)"]||r["bac_water_ml"])||null,
            standard_dose_iu:parseFloat(r["standard dose (iu)"]||r["standard_dose_iu"])||null,
            dose_unit:r["dose unit"]||r["dose_unit"]||"mcg",
            cost_paid:parseFloat(r["cost paid"]||r["cost_paid"])||null,
            notes:r["notes"]||null,
            dot:r["dot"]||null, shape:r["shape"]||"circle",
          });
          if(error) errors.push(`Vial "${name}": ${error.message}`);
          else vialsImported++;
        }
      }

      // ── Import Injection Log ─────────────────────────────────────────
      const logKey = Object.keys(sectionLines).find(k=>k.includes("LOG")||k.includes("INJECT"));
      if(logKey){
        const block = sectionLines[logKey].join("\n");
        const rows  = parseCSVBlock(block);
        for(const r of rows){
          const vialName = r["peptide"]||r["vial_name"]||r["vial name"]||r["name"];
          const injectedAt = r["injected at"]||r["injected_at"];
          if(!vialName || !injectedAt) continue;
          // Try to match to existing vial for vial_id + dot
          const matched = vials.find(v=>v.name.toLowerCase()===vialName.toLowerCase());
          const {error} = await supabase.from("injection_log").insert({
            user_id:userId,
            vial_id:matched?.id||null,
            vial_name:vialName,
            vial_dot:matched?.dot||null,
            dose_mcg:parseFloat(r["dose (mcg)"]||r["dose_mcg"])||null,
            dose_iu:parseFloat(r["iu"]||r["dose_iu"])||null,
            dose_ml:parseFloat(r["ml"]||r["dose_ml"])||null,
            injected_at:new Date(injectedAt).toISOString(),
            notes:r["notes"]||null,
          });
          if(error) errors.push(`Log entry "${vialName}": ${error.message}`);
          else logImported++;
        }
      }

      const parts = [];
      if(vialsImported>0) parts.push(`${vialsImported} vial${vialsImported!==1?"s":""}`);
      if(logImported>0)   parts.push(`${logImported} log entr${logImported!==1?"ies":"y"}`);

      if(parts.length===0 && errors.length===0){
        setImportMsg({type:"error",text:"No importable data found. Make sure the file is a PinPal export or follows the same column headers."});
      } else {
        setImportMsg({type:"success",text:`Imported ${parts.join(" and ")}.${errors.length>0?" Some rows skipped: "+errors.slice(0,2).join("; "):""}`});
        onImportDone(); // reload vials from Supabase
      }
    } catch(err){
      setImportMsg({type:"error",text:"Could not read file: "+err.message});
    }
    setImporting(false);
    if(fileRef.current) fileRef.current.value="";
  };

  return (
    <Modal open={open} onClose={()=>{onClose();setImportMsg(null);setTab("export");}} title="Data">
      <div style={{display:"flex",flexDirection:"column",gap:16}}>

        {/* Tab switcher */}
        <div style={{display:"flex",background:T.elevated,borderRadius:10,padding:3,gap:3}}>
          {[{id:"export",label:"Export",icon:"download"},{id:"import",label:"Import",icon:"upload"}].map(t=>(
            <button key={t.id} onClick={()=>{setTab(t.id);setImportMsg(null);}}
              style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",gap:6,padding:"9px",borderRadius:8,border:"none",cursor:"pointer",transition:"all .15s",
                background:tab===t.id?T.surface:"transparent",
                color:tab===t.id?T.text:T.textSub,fontWeight:700,fontSize:13}}>
              <Icon name={t.icon} size={14} color={tab===t.id?T.accent:T.textSub}/>
              {t.label}
            </button>
          ))}
        </div>

        {/* ── EXPORT TAB ── */}
        {tab==="export" && (
          <>
            <p style={{fontSize:14,color:T.text,margin:0}}>Downloads a <strong style={{color:T.accent}}>.csv</strong> with your full inventory and injection log.</p>
            {[{label:"Vials",count:vials.length,icon:"box"},{label:"Injection entries",count:entries.length,icon:"clock"}].map(r=>(
              <div key={r.label} style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:T.elevated,borderRadius:10,padding:"12px 14px"}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}><Icon name={r.icon} size={17} color={T.accent}/><span style={{fontSize:14,color:T.text}}>{r.label}</span></div>
                <Badge>{r.count} row{r.count!==1?"s":""}</Badge>
              </div>
            ))}
            <Btn variant={exportDone?"success":"primary"} icon={exportDone?"check":"download"} style={{width:"100%",justifyContent:"center"}} onClick={handleExport}>
              {exportDone?"Downloaded!":"Download CSV"}
            </Btn>
          </>
        )}

        {/* ── IMPORT TAB ── */}
        {tab==="import" && (
          <>
            <div style={{background:T.elevated,borderRadius:12,padding:"14px",display:"flex",flexDirection:"column",gap:8}}>
              <p style={{fontSize:14,color:T.text,margin:0,fontWeight:700}}>Import from CSV</p>
              <p style={{fontSize:13,color:T.textSub,margin:0}}>Works with PinPal exports or any CSV with matching column headers. Existing data is not overwritten — rows are added.</p>
              <div style={{fontSize:12,color:T.tip,marginTop:4}}>
                <strong>Inventory columns:</strong> Name, Total (mg), Remaining (mg), Status, BAC Water (mL), Standard Dose (IU), Notes<br/>
                <strong>Log columns:</strong> Peptide, Dose (mcg), IU, mL, Injected At, Notes
              </div>
            </div>

            {importMsg && (
              <div style={{background:importMsg.type==="success"?T.greenDim:T.redDim,border:`1px solid ${importMsg.type==="success"?T.green:T.red}44`,borderRadius:10,padding:"10px 14px",display:"flex",gap:8,alignItems:"flex-start"}}>
                <Icon name={importMsg.type==="success"?"check":"alert"} size={15} color={importMsg.type==="success"?T.green:T.red}/>
                <span style={{fontSize:13,color:importMsg.type==="success"?T.green:T.red,lineHeight:1.5}}>{importMsg.text}</span>
              </div>
            )}

            <input ref={fileRef} type="file" accept=".csv,text/csv" onChange={handleFile} style={{display:"none"}}/>
            <Btn loading={importing} icon="upload" style={{width:"100%",justifyContent:"center"}} onClick={()=>fileRef.current?.click()}>
              {importing?"Importing…":"Choose CSV File"}
            </Btn>
          </>
        )}

      </div>
    </Modal>
  );
};

// ══════════════════════════════════════════════════════════════════════════
// ROOT
// ══════════════════════════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════════════════
// COST MODULE
// ══════════════════════════════════════════════════════════════════════════
const Cost = ({vials, updateVial}) => {
  const [editId,  setEditId]  = useState(null);
  const [editVal, setEditVal] = useState("");
  const [saving,  setSaving]  = useState(false);

  const saveCost = async (v) => {
    setSaving(true);
    await updateVial(v.id, {
      name:v.name, totalMg:v.total_mg, remaining:v.remaining_mg,
      dot:v.dot, shape:v.shape||"circle", status:v.status||"powder",
      bacWaterMl:v.bac_water_ml, standardDoseIu:v.standard_dose_iu,
      doseUnit:v.dose_unit||"mcg", notes:v.notes,
      costPaid: editVal ? +editVal : null,
    });
    setSaving(false); setEditId(null); setEditVal("");
  };

  // Cost per dose calculation
  const cpd = (v) => {
    if(!v.cost_paid || !v.total_mg) return null;
    if(v.status === "reconstituted" && v.standard_dose_iu && v.bac_water_ml) {
      const mcgPerMl  = (v.total_mg * 1000) / v.bac_water_ml;
      const mlPerDose = v.standard_dose_iu / 100;
      const doseAmtMcg = mcgPerMl * mlPerDose;
      const totalDoses = (v.total_mg * 1000) / doseAmtMcg;
      return totalDoses > 0 ? v.cost_paid / totalDoses : null;
    }
    return null;
  };

  // Total inventory value = sum of all vials with cost
  const totalValue = vials.reduce((sum, v) => sum + (v.cost_paid || 0), 0);

  // Remaining value = cost * (remaining_mg / total_mg)
  const remainingValue = vials.reduce((sum, v) => {
    if(!v.cost_paid) return sum;
    return sum + v.cost_paid * (v.remaining_mg / v.total_mg);
  }, 0);

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>

      {/* Summary banner */}
      <Card style={{background:"linear-gradient(135deg,#1a2a1a,#1a1a2a)",borderColor:"rgba(79,158,255,.2)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div>
            <div style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.7,textTransform:"uppercase",marginBottom:4}}>Inventory Value</div>
            <div style={{fontSize:30,fontWeight:900,color:T.text,letterSpacing:-1}}>${totalValue.toFixed(2)}</div>
            <div style={{fontSize:12,color:T.textSub,marginTop:2}}>total paid across {vials.filter(v=>v.cost_paid).length} vial{vials.filter(v=>v.cost_paid).length!==1?"s":""}</div>
          </div>
          <div style={{textAlign:"right"}}>
            <div style={{fontSize:11,fontWeight:700,color:T.textSub,letterSpacing:.7,textTransform:"uppercase",marginBottom:4}}>Remaining</div>
            <div style={{fontSize:24,fontWeight:800,color:T.green,letterSpacing:-.5}}>${remainingValue.toFixed(2)}</div>
            <div style={{fontSize:12,color:T.textSub,marginTop:2}}>est. value left</div>
          </div>
        </div>
      </Card>

      {vials.length === 0 && (
        <Card style={{textAlign:"center",padding:48}}>
          <Icon name="dollar" size={38} color={T.textMute}/>
          <p style={{color:T.textSub,marginTop:12,fontSize:14}}>Add vials in Inventory first.</p>
        </Card>
      )}

      {/* Vial rows */}
      {vials.map(v => {
        const c    = cpd(v);
        const pct  = Math.max(0,Math.min(100,Math.round((v.remaining_mg/v.total_mg)*100)));
        const bar  = pct<25?T.red:pct<50?T.amber:T.green;
        const isEditing = editId === v.id;

        return (
          <Card key={v.id} style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              {v.dot && <DotIcon dot={v.dot} shape={v.shape||"circle"} size={9}/>}
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",alignItems:"baseline",gap:8,flexWrap:"wrap"}}>
                  <span style={{fontSize:15,fontWeight:800,color:T.text}}>{v.name}</span>
                  <StatusTag status={v.status}/>
                </div>
                {/* Mini progress bar */}
                <div style={{marginTop:5,height:3,background:T.elevated,borderRadius:99}}>
                  <div style={{height:3,borderRadius:99,width:`${pct}%`,background:bar}}/>
                </div>
                <div style={{display:"flex",justifyContent:"space-between",marginTop:4}}>
                  <span style={{fontSize:11,color:T.textSub}}>{v.remaining_mg} mg left ({pct}%)</span>
                  {c && <span style={{fontSize:11,color:T.tip,fontWeight:700}}>${c.toFixed(2)} / dose</span>}
                </div>
              </div>

              {/* Cost display / edit */}
              <div style={{display:"flex",alignItems:"center",gap:8,marginLeft:4}}>
                {isEditing ? (
                  <>
                    <div style={{display:"flex",alignItems:"center",background:T.elevated,borderRadius:8,border:`1.5px solid ${T.accent}`,overflow:"hidden"}}>
                      <span style={{paddingLeft:10,fontSize:14,color:T.textSub}}>$</span>
                      <input
                        type="number" inputMode="decimal" autoFocus
                        value={editVal}
                        onChange={e=>setEditVal(e.target.value)}
                        style={{width:70,padding:"8px 8px",fontSize:14,background:"transparent",border:"none",outline:"none",color:T.text,colorScheme:"dark"}}
                      />
                    </div>
                    <button onClick={()=>saveCost(v)} disabled={saving}
                      style={{background:T.green,border:"none",borderRadius:8,padding:"8px 10px",cursor:"pointer",display:"flex",alignItems:"center"}}>
                      <Icon name="check" size={14} color="#000"/>
                    </button>
                    <button onClick={()=>{setEditId(null);setEditVal("");}}
                      style={{background:T.elevated,border:"none",borderRadius:8,padding:"8px 10px",cursor:"pointer"}}>
                      <Icon name="x" size={14} color={T.textSub}/>
                    </button>
                  </>
                ) : (
                  <button onClick={()=>{setEditId(v.id);setEditVal(v.cost_paid||"");}}
                    style={{background:T.elevated,border:`1px solid ${T.border}`,borderRadius:8,padding:"7px 12px",cursor:"pointer",display:"flex",alignItems:"center",gap:6}}>
                    {v.cost_paid
                      ? <span style={{fontSize:14,fontWeight:700,color:T.text}}>${(+v.cost_paid).toFixed(2)}</span>
                      : <span style={{fontSize:13,color:T.textSub}}>Add cost</span>
                    }
                    <Icon name="edit" size={13} color={T.textSub}/>
                  </button>
                )}
              </div>
            </div>
          </Card>
        );
      })}

      <div style={{padding:"8px 0",textAlign:"center"}}>
        <span style={{fontSize:12,color:T.tip}}>Tap "Add cost" on any vial to enter what you paid. Cost per dose calculates automatically for reconstituted vials with a standard dose set.</span>
      </div>
    </div>
  );
};

const TABS = [
  {id:"calc",  label:"Calculator", icon:"flask"},
  {id:"inv",   label:"Inventory",  icon:"box"},
  {id:"cal",   label:"Calendar",   icon:"calendar"},
  {id:"log",   label:"Log",        icon:"clock"},
  {id:"cost",  label:"Cost",       icon:"dollar"},
];

export default function App() {
  const [user,        setUser]        = useState(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [tab,         setTab]         = useState("inv");
  const [dataOpen,    setDataOpen]    = useState(false);

  useEffect(()=>{
    supabase.auth.getSession().then(({data:{session}})=>{
      setUser(session?.user??null);
      setAuthLoading(false);
    });
    const {data:{subscription}} = supabase.auth.onAuthStateChange((_,session)=>{
      setUser(session?.user??null);
    });
    return ()=>subscription.unsubscribe();
  },[]);

  const {vials,loading:vialsLoading,addVial,updateVial,deductVial,deleteVial,reorderVials} = useVials(user?.id);
  // protocols removed
  const {entries,addEntry,deleteEntry}                                        = useLog(user?.id);

  const signOut = () => supabase.auth.signOut();

  if(authLoading) return <Spinner/>;
  if(!user)       return <AuthScreen onAuth={setUser}/>;

  const lowCount = vials.filter(v=>(v.remaining_mg/v.total_mg)<0.25).length;

  return (
    <div style={{minHeight:"100svh",background:T.bg,fontFamily:"-apple-system,'SF Pro Display',BlinkMacSystemFont,sans-serif",colorScheme:"dark",WebkitOverflowScrolling:"touch"}}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <DataModal open={dataOpen} onClose={()=>setDataOpen(false)} vials={vials} entries={entries} userId={user.id} onImportDone={()=>{ setTimeout(()=>window.location.reload(),400); }}/>

      <div style={{background:`${T.surface}f0`,backdropFilter:"blur(24px)",WebkitBackdropFilter:"blur(24px)",borderBottom:`1px solid ${T.border}`,position:"sticky",top:0,zIndex:50,paddingTop:"env(safe-area-inset-top)"}}>
        <div style={{maxWidth:680,margin:"0 auto",padding:"14px 20px 0"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <img src="data:image/png;base64," alt="PinPal" style={{width:36,height:36,borderRadius:9,display:"block",flexShrink:0}}/>
              <div>
                <h1 style={{fontSize:22,fontWeight:900,letterSpacing:-.7,color:T.text,margin:0,lineHeight:1.1}}>PinPal</h1>
                <p style={{fontSize:11,color:T.textMute,margin:0,letterSpacing:.3,maxWidth:180,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user.email}</p>
              </div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              {lowCount>0 && (
                <div style={{display:"flex",alignItems:"center",gap:5,background:T.redDim,borderRadius:10,padding:"6px 11px"}}>
                  <Icon name="alert" size={14} color={T.red}/>
                  <span style={{fontSize:12,fontWeight:700,color:T.red}}>{lowCount} low</span>
                </div>
              )}
              <button onClick={()=>setDataOpen(true)} title="Export / Import" style={{background:T.elevated,border:`1px solid ${T.border}`,borderRadius:10,width:36,height:36,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}>
                <Icon name="download" size={16} color={T.textSub}/>
              </button>
              <button onClick={signOut} title="Sign out" style={{background:T.elevated,border:`1px solid ${T.border}`,borderRadius:10,width:36,height:36,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}>
                <Icon name="logout" size={16} color={T.textSub}/>
              </button>
            </div>
          </div>

          <div style={{display:"flex"}}>
            {TABS.map(t=>(
              <button key={t.id} onClick={()=>setTab(t.id)} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4,padding:"8px 4px 12px",border:"none",background:"transparent",cursor:"pointer",borderBottom:`2px solid ${tab===t.id?T.accent:"transparent"}`,transition:"border-color .15s",WebkitTapHighlightColor:"transparent",minHeight:52}}>
                <Icon name={t.icon} size={19} color={tab===t.id?T.accent:T.textMute}/>
                <span style={{fontSize:10,fontWeight:700,letterSpacing:.3,color:tab===t.id?T.accent:T.textMute}}>{t.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{maxWidth:680,margin:"0 auto",padding:"18px 16px",paddingBottom:"calc(100px + env(safe-area-inset-bottom)"}}>
        {vialsLoading ? (
          <div style={{display:"flex",justifyContent:"center",padding:60}}>
            <div style={{width:28,height:28,border:`3px solid ${T.border}`,borderTopColor:T.accent,borderRadius:"50%",animation:"spin 0.7s linear infinite"}}/>
          </div>
        ) : <>
          {tab==="calc"  && <Calculator/>}
          {tab==="inv"   && <Inventory  vials={vials} addVial={addVial} updateVial={updateVial} deleteVial={deleteVial} reorderVials={reorderVials}/>}
          {tab==="cal"   && <Calendar   vials={vials} entries={entries}/>}
          {tab==="log"   && <Log        vials={vials} entries={entries} addEntry={addEntry} deleteEntry={deleteEntry} deductVial={deductVial}/>}
          {tab==="cost"  && <Cost       vials={vials} updateVial={updateVial}/>}
        </>}
      </div>
    </div>
  );
}
